B.a5l=new A.vP("M-01","BREATHING","\u0421\u0431\u0440\u043e\u0441 \u043d\u0435\u0440\u0432\u043d\u043e\u0439 \u0441\u0438\u0441\u0442\u0435\u043c\u044b","\u0414\u044b\u0445\u0430\u0442\u0435\u043b\u044c\u043d\u044b\u0435 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0438 \u043c\u043e\u0434\u0443\u043b\u044f SiE \u043e\u0441\u043d\u043e\u0432\u0430\u043d\u044b \u043d\u0430 \u043c\u0435\u0442\u043e\u0434\u0435 \u0412\u0438\u043c\u0430 \u0425\u043e\u0444\u0430 \u2014 \u0442\u0435\u0445\u043d\u0438\u043a\u0435 \u0433\u0438\u043f\u0435\u0440\u0432\u0435\u043d\u0442\u0438\u043b\u044f\u0446\u0438\u0438 \u0441 \u043f\u043e\u0441\u043b\u0435\u0434\u0443\u044e\u0449\u0435\u0439 \u0437\u0430\u0434\u0435\u0440\u0436\u043a\u043e\u0439 \u0434\u044b\u0445\u0430\u043d\u0438\u044f.\n\n\u0424\u0438\u0437\u0438\u043e\u043b\u043e\u0433\u0438\u0447\u0435\u0441\u043a\u0438: \u0441\u0435\u0440\u0438\u044f \u0431\u044b\u0441\u0442\u0440\u044b\u0445 \u0432\u0434\u043e\u0445\u043e\u0432 \u0441\u043d\u0438\u0436\u0430\u0435\u0442 \u0443\u0440\u043e\u0432\u0435\u043d\u044c CO\u2082 \u0432 \u043a\u0440\u043e\u0432\u0438, \u043f\u043e\u0432\u044b\u0448\u0430\u0435\u0442 pH (\u0430\u043b\u043a\u0430\u043b\u043e\u0437). \u0417\u0430\u0434\u0435\u0440\u0436\u043a\u0430 \u0434\u044b\u0445\u0430\u043d\u0438\u044f \u043d\u0430 \u0432\u044b\u0434\u043e\u0445\u0435 \u0432\u044b\u0437\u044b\u0432\u0430\u0435\u0442 \u0443\u043f\u0440\u0430\u0432\u043b\u044f\u0435\u043c\u044b\u0439 \u0433\u0438\u043f\u043e\u043a\u0441\u0438\u0447\u0435\u0441\u043a\u0438\u0439 \u0441\u0442\u0440\u0435\u0441\u0441, \u0441\u0442\u0438\u043c\u0443\u043b\u0438\u0440\u0443\u044f \u043c\u0438\u0442\u043e\u0445\u043e\u043d\u0434\u0440\u0438\u0430\u043b\u044c\u043d\u044b\u0435 \u0430\u0434\u0430\u043f\u0442\u0430\u0446\u0438\u0438 \u0438 \u0432\u044b\u0431\u0440\u043e\u0441 \u0430\u0434\u0440\u0435\u043d\u0430\u043b\u0438\u043d\u0430 \u0438\u0437 \u043d\u0430\u0434\u043f\u043e\u0447\u0435\u0447\u043d\u0438\u043a\u043e\u0432.\n\n\u0414\u043e\u043a\u0430\u0437\u0430\u043d\u043d\u044b\u0435 \u044d\u0444\u0444\u0435\u043a\u0442\u044b (\u0440\u0430\u043d\u0434\u043e\u043c\u0438\u0437\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0435 \u0438\u0441\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u044f):\n\u2192 \u0421\u043d\u0438\u0436\u0435\u043d\u0438\u0435 \u0441\u0443\u0431\u044a\u0435\u043a\u0442\u0438\u0432\u043d\u043e\u0433\u043e \u0441\u0442\u0440\u0435\u0441\u0441\u0430 \u0434\u043e 30% \u0443\u0436\u0435 \u043f\u043e\u0441\u043b\u0435 \u043e\u0434\u043d\u043e\u0439 \u0441\u0435\u0441\u0441\u0438\u0438\n\u2192 \u041f\u043e\u0432\u044b\u0448\u0435\u043d\u0438\u0435 \u0431\u043e\u043b\u0435\u0432\u043e\u0433\u043e \u043f\u043e\u0440\u043e\u0433\u0430 \u0438 \u0438\u043c\u043c\u0443\u043d\u043d\u043e\u0433\u043e \u043e\u0442\u0432\u0435\u0442\u0430\n\u2192 \u0423\u043b\u0443\u0447\u0448\u0435\u043d\u0438\u0435 \u044d\u043d\u0435\u0440\u0433\u0435\u0442\u0438\u0447\u0435\u0441\u043a\u043e\u0433\u043e \u0442\u043e\u043d\u0443\u0441\u0430 \u0437\u0430 \u0441\u0447\u0451\u0442 \u043d\u0430\u0441\u044b\u0449\u0435\u043d\u0438\u044f \u0442\u043a\u0430\u043d\u0435\u0439 \u043a\u0438\u0441\u043b\u043e\u0440\u043e\u0434\u043e\u043c\n\n\u0420\u0435\u043a\u043e\u043c\u0435\u043d\u0434\u043e\u0432\u0430\u043d\u043d\u044b\u0439 \u043f\u0440\u043e\u0442\u043e\u043a\u043e\u043b: 3 \u0440\u0430\u0443\u043d\u0434\u0430 \u043f\u043e 30 \u0446\u0438\u043a\u043b\u043e\u0432. \u041c\u0438\u043d\u0438\u043c\u0430\u043b\u044c\u043d\u0430\u044f \u044d\u0444\u0444\u0435\u043a\u0442\u0438\u0432\u043d\u0430\u044f \u0441\u0435\u0441\u0441\u0438\u044f \u2014 30 \u0441\u0435\u043a\u0443\u043d\u0434 \u0430\u043a\u0442\u0438\u0432\u043d\u043e\u0439 \u043f\u0440\u0430\u043a\u0442\u0438\u043a\u0438.",null)
